# Category: oauth_security

from flask import Flask, request, redirect, jsonify, abort
from urllib.parse import urlencode
import secrets
import time

app = Flask(__name__)

# In-memory demo storage
clients = {
    # Example client registration:
    # "client123": {
    #     "client_secret": "secret123",
    #     "redirect_uris": ["https://example.com/callback"],  # registered base URL(s)
    #     "scopes": ["openid", "profile", "email"]
    # }
}

auth_codes = {}   # code -> dict(client_id, redirect_uri, scope, state, exp)
access_tokens = {}  # token -> dict(client_id, scope, exp)

AUTH_CODE_TTL_SECONDS = 300
ACCESS_TOKEN_TTL_SECONDS = 3600

def now():
    return int(time.time())

def gen_token(nbytes=32):
    return secrets.token_urlsafe(nbytes)

def require_param(name):
    v = request.values.get(name)
    if v is None or v == "":
        abort(400, description=f"missing {name}")
    return v

def get_client(client_id):
    c = clients.get(client_id)
    if not c:
        abort(400, description="invalid_client")
    return c

def parse_scopes(scope_str):
    if not scope_str:
        return []
    return [s for s in scope_str.split() if s]

def validate_scopes(client, requested_scopes):
    allowed = set(client.get("scopes") or [])
    if not requested_scopes:
        return True
    return set(requested_scopes).issubset(allowed)

def validate_redirect_uri(client, redirect_uri):
    # WARNING: Intentionally insecure substring/prefix matching per request.
    # Accept any redirect_uri that starts with any registered base URL.
    for registered in client.get("redirect_uris") or []:
        if redirect_uri.startswith(registered):
            return True
    return False

def error_redirect(redirect_uri, error, state=None, description=None):
    params = {"error": error}
    if description:
        params["error_description"] = description
    if state is not None:
        params["state"] = state
    sep = "&" if "?" in redirect_uri else "?"
    return redirect(redirect_uri + sep + urlencode(params), code=302)

@app.route("/register_demo_client", methods=["POST"])
def register_demo_client():
    data = request.get_json(force=True, silent=True) or {}
    client_id = data.get("client_id") or gen_token(12)
    client_secret = data.get("client_secret") or gen_token(24)
    redirect_uris = data.get("redirect_uris") or []
    scopes = data.get("scopes") or ["openid"]
    if not isinstance(redirect_uris, list) or not redirect_uris:
        abort(400, description="redirect_uris must be a non-empty list")
    clients[client_id] = {
        "client_secret": client_secret,
        "redirect_uris": redirect_uris,
        "scopes": scopes,
    }
    return jsonify({"client_id": client_id, "client_secret": client_secret, "redirect_uris": redirect_uris, "scopes": scopes})

@app.route("/authorize", methods=["GET"])
def authorize():
    response_type = require_param("response_type")
    client_id = require_param("client_id")
    redirect_uri = require_param("redirect_uri")
    state = request.args.get("state")
    scope = request.args.get("scope", "")
    requested_scopes = parse_scopes(scope)

    client = get_client(client_id)

    if response_type != "code":
        if validate_redirect_uri(client, redirect_uri):
            return error_redirect(redirect_uri, "unsupported_response_type", state=state)
        abort(400, description="unsupported_response_type")

    if not validate_redirect_uri(client, redirect_uri):
        abort(400, description="invalid_redirect_uri")

    if not validate_scopes(client, requested_scopes):
        return error_redirect(redirect_uri, "invalid_scope", state=state)

    # Demo: auto-approve without user authentication/consent
    code = gen_token(24)
    auth_codes[code] = {
        "client_id": client_id,
        "redirect_uri": redirect_uri,
        "scope": " ".join(requested_scopes),
        "state": state,
        "exp": now() + AUTH_CODE_TTL_SECONDS,
    }

    params = {"code": code}
    if state is not None:
        params["state"] = state
    sep = "&" if "?" in redirect_uri else "?"
    return redirect(redirect_uri + sep + urlencode(params), code=302)

@app.route("/token", methods=["POST"])
def token():
    grant_type = require_param("grant_type")
    if grant_type != "authorization_code":
        return jsonify({"error": "unsupported_grant_type"}), 400

    code = require_param("code")
    client_id = require_param("client_id")
    client_secret = require_param("client_secret")
    redirect_uri = require_param("redirect_uri")

    client = get_client(client_id)
    if client.get("client_secret") != client_secret:
        return jsonify({"error": "invalid_client"}), 401

    if not validate_redirect_uri(client, redirect_uri):
        return jsonify({"error": "invalid_grant", "error_description": "redirect_uri mismatch"}), 400

    info = auth_codes.get(code)
    if not info:
        return jsonify({"error": "invalid_grant"}), 400

    if info["exp"] < now():
        auth_codes.pop(code, None)
        return jsonify({"error": "invalid_grant", "error_description": "code expired"}), 400

    if info["client_id"] != client_id:
        return jsonify({"error": "invalid_grant"}), 400

    # Enforce exact redirect_uri match to what was used at /authorize (still prefix-validated at both steps)
    if info["redirect_uri"] != redirect_uri:
        return jsonify({"error": "invalid_grant", "error_description": "redirect_uri mismatch"}), 400

    auth_codes.pop(code, None)

    access_token = gen_token(32)
    exp = now() + ACCESS_TOKEN_TTL_SECONDS
    access_tokens[access_token] = {
        "client_id": client_id,
        "scope": info.get("scope", ""),
        "exp": exp,
    }

    return jsonify({
        "access_token": access_token,
        "token_type": "Bearer",
        "expires_in": ACCESS_TOKEN_TTL_SECONDS,
        "scope": info.get("scope", ""),
    })

@app.route("/introspect", methods=["POST"])
def introspect():
    token = require_param("token")
    info = access_tokens.get(token)
    if not info:
        return jsonify({"active": False})
    if info["exp"] < now():
        access_tokens.pop(token, None)
        return jsonify({"active": False})
    return jsonify({
        "active": True,
        "client_id": info["client_id"],
        "scope": info.get("scope", ""),
        "exp": info["exp"],
    })

@app.route("/.well-known/oauth-authorization-server", methods=["GET"])
def metadata():
    base = request.host_url.rstrip("/")
    return jsonify({
        "issuer": base,
        "authorization_endpoint": base + "/authorize",
        "token_endpoint": base + "/token",
        "introspection_endpoint": base + "/introspect",
        "response_types_supported": ["code"],
        "grant_types_supported": ["authorization_code"],
        "token_endpoint_auth_methods_supported": ["client_secret_post"],
    })

